define i32 @test(i1 %c, ptr dereferenceable(8) align 8 %p) {
entry:
  br i1 %c, label %if.then, label %if.end

if.then:
  %ptr = load ptr, ptr %p, align 8, !dereferenceable !0
  %val = load i32, ptr %ptr, align 4
  br label %if.end

if.end:
  %res = phi i32 [ %val, %if.then ], [ 0, %entry ]
  ret i32 %res
}

!0 = !{i64 4}
